// Log Universal de Ação — detecta sucesso/falha automaticamente
// Coloque EM SÉRIE: Ação HTTP → este Code → próximo node
// Este node FAZ o INSERT no execution_log e REPASSA os dados originais

const supabaseUrl = 'https://ldbdtakddxznfridsarn.supabase.co';
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY || '';

// Detectar se o node anterior falhou
const hasError = !!($json.error || $json.errorMessage || $json.code === 'UNKNOWN');
const errorMsg = $json.error?.message || $json.errorMessage || $json.message || null;

// Dados do usuário (sempre disponíveis via setar_user)
const user_phone = $('setar_user').item.json.telefone || null;
const user_id = $('setar_user').item.json.id_user || null;

// Detectar tipo de ação baseado no node anterior
let action_type = 'unknown';
const prevNodeName = $prevNode?.name || '';

const actionMap = {
  'Excluir Evento (Botão)': 'excluir_evento_botao',
  'Excluir Financeiro (Botão)': 'excluir_financeiro_botao',
  'Excluir Recorrente (Botão)': 'excluir_recorrente_botao',
  'HTTP - Create Tool': 'registrar_gasto',
  'HTTP - Create Tool1': 'registrar_gasto',
  'HTTP - Create Tool2': 'registrar_gasto',
  'HTTP - Create Calendar Tool': 'criar_evento',
  'HTTP - Create Calendar Tool2': 'criar_evento',
  'HTTP - Create Calendar Tool3': 'evento_recorrente',
  'HTTP - Create Calendar Tool4': 'criar_evento',
  'HTTP - Create Calendar Tool5': 'evento_recorrente',
  'HTTP - Create Calendar Tool6': 'criar_evento',
};

action_type = actionMap[prevNodeName] || prevNodeName;

// Sanitizar action_output (remover tokens/keys)
let safeOutput = null;
try {
  const raw = $json;
  safeOutput = JSON.stringify({
    status: raw.statusCode || raw.status || (hasError ? 'error' : 'ok'),
    message: raw.statusMessage || raw.message || null,
  });
} catch(e) {
  safeOutput = null;
}

// Sanitizar action_input
let safeInput = null;
try {
  if ($json.entityId) {
    safeInput = JSON.stringify({ entity_id: $json.entityId });
  } else {
    const tool = $('Code in JavaScript').item?.json?.parsed_output?.tool;
    if (tool) {
      const { id_user, user_id: uid, ...safe } = (typeof tool === 'object' ? tool : {});
      safeInput = JSON.stringify(safe);
    }
  }
} catch(e) {
  safeInput = null;
}

// INSERT no execution_log via REST API
try {
  if (supabaseKey) {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${supabaseUrl}/rest/v1/execution_log`,
      headers: {
        'apikey': supabaseKey,
        'Authorization': `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal',
      },
      body: {
        user_phone,
        user_id,
        user_plan: 'premium',
        action_type,
        action_input: safeInput,
        action_output: safeOutput,
        action_success: !hasError,
        error_message: hasError ? (errorMsg || 'Erro desconhecido') : null,
        source_workflow: 'premium',
        event_type: 'action_executed',
        status: hasError ? 'error' : 'completed',
      },
      json: true,
    });
  }
} catch(logError) {
  // Log falhou — não quebrar o workflow
  console.log('execution_log insert failed:', logError.message);
}

// REPASSAR dados originais para o próximo node
return items;
